// From: /home/user/project/node_modules/@trpc/client/dist/index.d.mts (line ~120)
// Source: /home/user/project/node_modules/@trpc/client/src/links/httpSubscriptionLink.ts

type HTTPSubscriptionLinkOptions<
  TRoot extends AnyClientTypes,
  TEventSource extends EventSourceLike.AnyConstructor = typeof EventSource,
> = {
  /** EventSource ponyfill */
  EventSource?: TEventSource;
  /** EventSource options or a callback that returns them */
  eventSourceOptions?:
    | EventSourceLike.InitDictOf<TEventSource>
    | ((opts: {
        op: Operation;
